        @mcp.tool()
        async def psd_update_text_layer(
            input_filename: str,
            new_text: str,
            layer_name: str | None = None,
            layer_index: int | None = None,
            output_filename: str | None = None,
        ) -> dict:
            """
            Update the text of a specific text layer inside a PSD/PSB file.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.psd') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the source PSD/PSB file, e.g. "design.psd".
                new_text: New text content that will replace the existing layer text.
                layer_name: Optional name of the text layer to update. The first layer whose name matches is used.
                layer_index: Optional zero‑based index of the layer to update. Used only when layer_name is None.
                output_filename: Optional bare filename for the resulting PSD/PSB. If omitted, a name is generated automatically.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str,          # bare name of the written file (or empty on error)
                    "output_path": str,              # absolute path where the file was written (or empty on error)
                    "updated_layer": str | None      # name of the layer that was modified (or None)
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist in ASPOSE_FILES_PATH.
                ValueError: If no matching text layer is found.
                Exception: Any unexpected error from the Aspose.PSD library.
        
            Example:
                result = await psd_update_text_layer(
                    input_filename="logo.psd",
                    new_text="New Company Name",
                    layer_name="CompanyName",
                    output_filename="logo_updated.psd"
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input / output filenames (no Aspose imports yet)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # sanitize optional output filename
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary output file inside ASPOSE_FILES_PATH
                resolved_output = str(temp_output_path("aspose_psd_result", ".psd"))
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose.PSD processing
            # ----------------------------------------------------------------------
            try:
                # Lazy Aspose imports
                from aspose.psd import Image
                from aspose.psd.fileformats.psd import PsdImage
                from aspose.psd.fileformats.psd.layers import TextLayer
                from aspose.psd.imageoptions import PsdOptions
                from aspose.pycore import cast
        
                updated_layer_name: str | None = None
        
                with Image.load(str(resolved_input)) as image:
                    psd_image = cast(PsdImage, image)
        
                    for i, layer in enumerate(psd_image.layers):
                        if not isinstance(layer, TextLayer):
                            continue
        
                        # layer name filter
                        if layer_name is not None and layer.name != layer_name:
                            continue
        
                        # layer index filter (only when name not supplied)
                        if layer_name is None and layer_index is not None and i != layer_index:
                            continue
        
                        text_layer = cast(TextLayer, layer)
                        text_layer.update_text(new_text)
                        updated_layer_name = layer.name
                        break
        
                    if updated_layer_name is None:
                        raise ValueError("No matching text layer found for the given criteria.")
        
                    psd_image.save(str(resolved_output), PsdOptions())
        
                return {
                    "status": "success",
                    "message": f"Text layer updated successfully; saved to '{output_filename}'.",
                    "output_filename": output_filename,
                    "output_path": resolved_output,
                    "updated_layer": updated_layer_name,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to update PSD text layer")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": "",
                    "output_path": "",
                    "updated_layer": None,
                }

