        @mcp.tool()
        async def psd_resize(
            input_filename: str,
            width: int,
            height: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Resize a PSD/PSB image to the specified dimensions.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: PSD/PSB filename only, located in ASPOSE_FILES_PATH.
                width: Target width in pixels (must be > 0).
                height: Target height in pixels (must be > 0).
                output_filename: Optional output filename. If None, a name is auto‑generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str,   # bare name of the written file
                    "output_path": str,       # absolute path on the server
                    "new_width": int,
                    "new_height": int
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                ValueError: If width or height are not positive integers.
                Exception: Propagated as an error status in the return dict.
        
            Example:
                result = await psd_resize("example.psd", 800, 600, "example_resized.psd")
            """
            # -------------------------------------------------------------------------
            # Imports that are NOT Aspose – must appear before any Aspose import
            # -------------------------------------------------------------------------
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # -------------------------------------------------------------------------
            # Validate and resolve input filename
            # -------------------------------------------------------------------------
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # -------------------------------------------------------------------------
            # Validate dimensions
            # -------------------------------------------------------------------------
            if width <= 0 or height <= 0:
                raise ValueError("Width and height must be positive integers.")
        
            # -------------------------------------------------------------------------
            # Resolve output filename / path
            # -------------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
        
            if output_filename:
                resolved_output = get_safe_path(output_filename)
            else:
                resolved_output = str(temp_output_path("aspose_psd_result", ".psd"))
                output_filename = Path(resolved_output).name
        
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Aspose imports – lazy, inside the function
            # -------------------------------------------------------------------------
            from aspose.psd import Image, ResizeType
            from aspose.psd.fileformats.psd import PsdImage
            from aspose.psd.imageoptions import PsdOptions
            from aspose.pycore import cast
        
            # -------------------------------------------------------------------------
            # Perform resize
            # -------------------------------------------------------------------------
            try:
                with Image.load(str(resolved_input)) as img:
                    psd_image = cast(PsdImage, img)
                    psd_image.resize(width, height, ResizeType.LANCZOS_RESAMPLE)
                    psd_image.save(str(resolved_output), PsdOptions())
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to resize PSD image.")
                return {"status": "error", "message": str(exc)}
        
            return {
                "status": "success",
                "message": f"Resized PSD saved as {output_filename}",
                "output_filename": output_filename,
                "output_path": resolved_output,
                "new_width": width,
                "new_height": height,
            }

        @mcp.tool()
        async def psd_crop(
            input_filename: str,
            x: int,
            y: int,
            width: int,
            height: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Crop a region from a PSD/PSB file and save it as PNG.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path,
              no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename
              is the bare name only.
        
            Args:
                input_filename: Bare filename of the PSD/PSB to crop, e.g. "design.psd".
                x: Left offset of the crop region in pixels.
                y: Top offset of the crop region in pixels.
                width: Width of the crop region in pixels.
                height: Height of the crop region in pixels.
                output_filename: Optional bare filename for the cropped PNG.
                                 If None, a name like "<input>_cropped.png" is generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written PNG (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                ValueError: If the crop rectangle is outside the image bounds.
                Exception: Any unexpected error from the Aspose library.
        
            Example:
                result = await psd_crop(
                    input_filename="logo.psd",
                    x=10,
                    y=20,
                    width=200,
                    height=100,
                    output_filename="logo_cropped.png"
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename (strip nulls, keep only name)
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output filename / path
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            else:
                output_filename = f"{Path(input_filename).stem}_cropped.png"
        
            resolved_output = get_safe_path(output_filename)
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Perform cropping using Aspose.PSD
            # ----------------------------------------------------------------------
            try:
                # Lazy import of Aspose modules
                from aspose.psd import Image, Rectangle
                from aspose.psd.fileformats.psd import PsdImage
                from aspose.psd.imageoptions import PngOptions
                from aspose.pycore import cast
        
                with Image.load(str(resolved_input)) as img:
                    psd_image = cast(PsdImage, img)
        
                    # Validate crop rectangle against image dimensions
                    img_width = getattr(psd_image, "width", None)
                    img_height = getattr(psd_image, "height", None)
                    if img_width is not None and img_height is not None:
                        if x < 0 or y < 0 or width <= 0 or height <= 0:
                            raise ValueError("Crop dimensions must be positive and offsets non‑negative.")
                        if x + width > img_width or y + height > img_height:
                            raise ValueError(
                                f"Crop rectangle ({x},{y},{width},{height}) exceeds image bounds "
                                f"({img_width}x{img_height})."
                            )
        
                    psd_image.crop(Rectangle(x, y, width, height))
                    psd_image.save(str(resolved_output), PngOptions())
        
                return {
                    "status": "success",
                    "message": "PSD cropped and saved as PNG.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # catch Aspose and any other errors
                logger.exception("Error cropping PSD file")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def psd_rotate(
            input_filename: str,
            degrees: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Rotate a PSD/PSB image and save as PNG.
        
            IMPORTANT:
            - All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            - The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            - Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            - The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename (str): PSD/PSB filename only, e.g. 'design.psd'.
                degrees (int): Rotation angle; must be 90, 180, or 270.
                output_filename (str | None, optional): Desired output filename. If None, a name is generated automatically with a .png extension.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str,
                    "output_path": str
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                ValueError: If `degrees` is not one of the allowed values.
        
            Example:
                await psd_rotate("logo.psd", 90)
            """
            # ----------------------------------------------------------------------
            # Validate and resolve input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename (bare name only)
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Prepare output filename and path
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            else:
                output_filename = f"{Path(input_filename).stem}_rot{degrees}.png"
        
            resolved_output = get_safe_path(output_filename)
            # ensure the directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose imports (lazy)
            # ----------------------------------------------------------------------
            from aspose.psd import Image, RotateFlipType
            from aspose.psd.fileformats.psd import PsdImage
            from aspose.psd.imageoptions import PngOptions
            from aspose.pycore import cast
        
            # ----------------------------------------------------------------------
            # Validate rotation angle
            # ----------------------------------------------------------------------
            _rotate_map = {
                90: RotateFlipType.ROTATE90_FLIP_NONE,
                180: RotateFlipType.ROTATE180_FLIP_NONE,
                270: RotateFlipType.ROTATE270_FLIP_NONE,
            }
            if degrees not in _rotate_map:
                raise ValueError(f"degrees must be 90, 180, or 270 — got {degrees}")
        
            # ----------------------------------------------------------------------
            # Perform rotation
            # ----------------------------------------------------------------------
            try:
                with Image.load(str(resolved_input)) as img:
                    psd_image = cast(PsdImage, img)
                    psd_image.rotate_flip(_rotate_map[degrees])
                    psd_image.save(str(resolved_output), PngOptions())
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to rotate PSD image")
                return {"status": "error", "message": str(exc), "output_filename": "", "output_path": ""}
        
            # ----------------------------------------------------------------------
            # Return result
            # ----------------------------------------------------------------------
            return {
                "status": "success",
                "message": f"Image rotated {degrees}° and saved as PNG.",
                "output_filename": output_filename,
                "output_path": resolved_output,
            }

        @mcp.tool()
        async def psd_add_text_watermark(
            input_filename: str,
            text: str,
            opacity: float | None = None,
            output_filename: str | None = None,
        ) -> dict:
            """
            Add a semi‑transparent text watermark to a PSD/PSB image and save as PNG.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the PSD/PSB file to watermark. Must exist in ASPOSE_FILES_PATH.
                text: Watermark text to draw on the image.
                opacity: Optional opacity between 0.0 and 1.0. Defaults to 0.5 if omitted.
                output_filename: Optional bare filename for the resulting PNG. If omitted, a name is auto‑generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                Exception: Any unexpected error from Aspose.PSD processing.
        
            Example:
                result = await psd_add_text_watermark(
                    input_filename="example.psd",
                    text="CONFIDENTIAL",
                    opacity=0.3,
                    output_filename="example_watermarked.png"
                )
            """
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # ---- Validate and resolve input file ----
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ---- Prepare output file ----
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary PNG filename
                resolved_output = str(temp_output_path("aspose_psd_result", ".png"))
                output_filename = Path(resolved_output).name
        
            # Ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ---- Lazy Aspose imports (after path handling) ----
            from aspose.psd import Image, Graphics, Font, SolidBrush, Color, PointF
            from aspose.psd.fileformats.psd import PsdImage
            from aspose.psd.imageoptions import PngOptions
            from aspose.pycore import cast
        
            try:
                # Compute alpha channel from opacity (default 0.5)
                alpha = int((opacity if opacity is not None else 0.5) * 255)
        
                with Image.load(str(resolved_input)) as img:
                    psd_image = cast(PsdImage, img)
                    graphics = Graphics(psd_image)
        
                    # Simple font and brush setup
                    font = Font('Arial', 36)
                    brush = SolidBrush(Color.from_argb(alpha, 255, 0, 0))
        
                    # Position watermark roughly at centre‑left
                    x_pos = psd_image.width / 4
                    y_pos = psd_image.height / 2
        
                    graphics.draw_string(text, font, brush, PointF(x_pos, y_pos))
        
                    # Save as PNG
                    psd_image.save(str(resolved_output), PngOptions())
        
                return {
                    "status": "success",
                    "message": f"Watermark added and saved to {output_filename}",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to add watermark to PSD")
                return {
                    "status": "error",
                    "message": str(exc),
                }
